def create_article_dict(file_path):
  article_dict = {}

  try:
    with open(file_path, 'r', encoding='utf-8') as file:
      content = file.read()

    # Разделяем содержимое на строки
    lines = content.strip().split("\n")

    for line in lines:
      # Разделяем каждую строку на части: номер, название и URL
      parts = line.split(" ")
      index = parts[0]  # Номер статьи
      title = " ".join(parts[1:-1]).rstrip(".?! ").replace("?",'').replace('\"',"")  # Название без знаков препинания
      url = parts[-1]  # URL

      # Добавляем в словарь
      article_dict[title] = url

  except Exception as e:
    print(f"Ошибка при чтении файла: {e}")

  return article_dict


# Пример использования функции
file_path = 'Статьи Ольги Александровны.txt'
articles = create_article_dict(file_path)
print(articles)
